m09-concurrency/async-await.solution:
@MainActor
func carregarPerfil(id: UUID) async {
    carregando = true
    defer { carregando = false }  // executa SEMPRE no final

    do {
        perfil = try await PerfilService.buscar(id: id)
        erro = nil
    } catch {
        self.erro = error.localizedDescription
        perfil = nil
    }
}

defer garante que carregando = false executa mesmo se um erro for lançado — evita o estado de loading travado.

m09-concurrency/mainactor-and-actors.prompt:
Este código pode gerar um warning 'Publishing changes from background thread'. Encontre e corrija:

class PerfilViewModel: ObservableObject {
    @Published var perfil: Perfil?

    func carregar(id: UUID) {
        Task {
            let resultado = try? await APIService.buscar(id: id)
